package v2

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// +genclient
// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object
// +deepequal-gen:private-method=true
// +kubebuilder:resource:categories={cilium},singular="ciliumpolicyquota",path="ciliumpolicyquotas",scope="Namespaced",shortName={cpq}
// +kubebuilder:storageversion

// CiliumPolicyQuota is a Kubernetes resource that enforces per-namespace limits
// on the number of CiliumNetworkPolicy resources, preventing policy sprawl in
// multi-tenant clusters.
type CiliumPolicyQuota struct {
	// +deepequal-gen=false
	metav1.TypeMeta `json:",inline"`
	// +deepequal-gen=false
	metav1.ObjectMeta `json:"metadata"`

	// Spec is the desired Cilium policy quota specification.
	Spec CiliumPolicyQuotaSpec `json:"spec"`

	// Status is the status of the Cilium policy quota.
	//
	// +kubebuilder:validation:Optional
	Status CiliumPolicyQuotaStatus `json:"status,omitempty"`
}

// +deepequal-gen=true

// CiliumPolicyQuotaSpec defines the policy quota specification.
type CiliumPolicyQuotaSpec struct {
	// MaxPoliciesPerNamespace is the maximum number of CiliumNetworkPolicy
	// resources allowed per namespace.
	MaxPoliciesPerNamespace int `json:"maxPoliciesPerNamespace"`
}

// +deepequal-gen=true

// CiliumPolicyQuotaStatus defines the status of a policy quota.
type CiliumPolicyQuotaStatus struct {
	// CurrentPoliciesPerNamespace contains the current count of policies per namespace.
	CurrentPoliciesPerNamespace map[string]int `json:"currentPoliciesPerNamespace,omitempty"`

	// EnforcedNamespaces is the list of namespaces where the quota is being enforced.
	EnforcedNamespaces []string `json:"enforcedNamespaces,omitempty"`
}

// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object
// +k8s:openapi-gen=false
// +deepequal-gen=false

// CiliumPolicyQuotaList is a list of CiliumPolicyQuota objects.
type CiliumPolicyQuotaList struct {
	// +deepequal-gen=false
	metav1.TypeMeta `json:",inline"`
	// +deepequal-gen=false
	metav1.ListMeta `json:"metadata,omitempty"`
	Items           []CiliumPolicyQuota `json:"items"`
}

