// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"errors"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var (
	log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

	// ErrQuotaExceeded is returned when a namespace quota for policies has been exceeded
	ErrQuotaExceeded = errors.New("policy quota exceeded for namespace")
)

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources, preventing policy sprawl in multi-tenant clusters.
type PolicyQuotaController struct {
	logger logrus.FieldLogger

	// maxPerNamespace is the maximum number of CiliumNetworkPolicy resources
	// allowed per namespace
	maxPerNamespace int

	// policyCounts tracks the number of policies per namespace
	policyCounts map[string]int

	// policyKeys tracks the set of policies we've already counted
	// to avoid double-counting on updates
	policyKeys map[resource.Key]struct{}
	mu         sync.RWMutex

	// ciliumNetworkPolicies is the resource for watching CiliumNetworkPolicy objects
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		logger:                log,
		maxPerNamespace:       maxPerNamespace,
		policyCounts:          make(map[string]int),
		policyKeys:            make(map[resource.Key]struct{}),
		ciliumNetworkPolicies: ciliumNetworkPolicies,
	}
}

// Run starts the controller and watches for changes to CiliumNetworkPolicy resources.
// It blocks until the context is cancelled.
func (p *PolicyQuotaController) Run(ctx context.Context) error {
	p.logger.Info("Starting PolicyQuotaController")

	// Get events from the CiliumNetworkPolicy resource
	events := p.ciliumNetworkPolicies.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			p.logger.Info("Stopping PolicyQuotaController")
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				p.logger.Info("Event channel closed")
				return nil
			}

			if event.Kind == resource.Sync {
				p.logger.Debug("Received sync event, controller is synchronized")
				event.Done(nil)
				continue
			}

			policy := event.Object
			namespace := policy.GetNamespace()

			switch event.Kind {
			case resource.Upsert:
				// Only count the policy if we haven't seen it before
				if p.addPolicyKey(event.Key) {
					// Check quota before allowing the policy
					if err := p.CheckQuota(namespace); err != nil {
						p.logger.WithFields(logrus.Fields{
							logfields.K8sNamespace: namespace,
							logfields.K8sObjName:   policy.GetName(),
							"policy_count":         p.getPolicyCount(namespace),
							"max_per_namespace":    p.maxPerNamespace,
						}).Warn("Policy quota exceeded")
						// Remove the key since we're rejecting it
						p.removePolicyKey(event.Key)
						event.Done(err)
						continue
					}

					p.incrementPolicyCount(namespace)
					p.logger.WithFields(logrus.Fields{
						logfields.K8sNamespace: namespace,
						logfields.K8sObjName:   policy.GetName(),
						"policy_count":         p.getPolicyCount(namespace),
					}).Debug("Policy added")
				}

			case resource.Delete:
				// Only decrement if we were tracking this policy
				if p.removePolicyKey(event.Key) {
					p.decrementPolicyCount(namespace)
					p.logger.WithFields(logrus.Fields{
						logfields.K8sNamespace: namespace,
						logfields.K8sObjName:   policy.GetName(),
						"policy_count":         p.getPolicyCount(namespace),
					}).Debug("Policy deleted")
				}
			}

			event.Done(nil)
		}
	}
}

// CheckQuota checks if a policy can be created in the given namespace.
// It returns an error if the namespace quota has been exceeded.
func (p *PolicyQuotaController) CheckQuota(namespace string) error {
	p.mu.RLock()
	defer p.mu.RUnlock()

	currentCount := p.policyCounts[namespace]
	if currentCount >= p.maxPerNamespace {
		return fmt.Errorf("%w: namespace=%s, current=%d, max=%d",
			ErrQuotaExceeded, namespace, currentCount, p.maxPerNamespace)
	}

	return nil
}

// addPolicyKey adds a policy key to the tracking set.
// Returns true if this is a new key (first time seeing it), false otherwise.
func (p *PolicyQuotaController) addPolicyKey(key resource.Key) bool {
	p.mu.Lock()
	defer p.mu.Unlock()

	if _, exists := p.policyKeys[key]; exists {
		return false
	}

	p.policyKeys[key] = struct{}{}
	return true
}

// removePolicyKey removes a policy key from the tracking set.
// Returns true if the key was in the set (and thus we decrement), false otherwise.
func (p *PolicyQuotaController) removePolicyKey(key resource.Key) bool {
	p.mu.Lock()
	defer p.mu.Unlock()

	if _, exists := p.policyKeys[key]; !exists {
		return false
	}

	delete(p.policyKeys, key)
	return true
}

// incrementPolicyCount increments the policy count for a namespace.
func (p *PolicyQuotaController) incrementPolicyCount(namespace string) {
	p.mu.Lock()
	defer p.mu.Unlock()

	p.policyCounts[namespace]++
}

// decrementPolicyCount decrements the policy count for a namespace.
// It does not allow the count to go below 0.
func (p *PolicyQuotaController) decrementPolicyCount(namespace string) {
	p.mu.Lock()
	defer p.mu.Unlock()

	if p.policyCounts[namespace] > 0 {
		p.policyCounts[namespace]--
	}
}

// getPolicyCount returns the current policy count for a namespace.
// This is a helper method that requires the lock to already be held.
func (p *PolicyQuotaController) getPolicyCount(namespace string) int {
	p.mu.RLock()
	defer p.mu.RUnlock()

	return p.policyCounts[namespace]
}

// GetNamespacePolicyCounts returns a copy of the current policy counts per namespace.
// This method is primarily useful for testing and monitoring.
func (p *PolicyQuotaController) GetNamespacePolicyCounts() map[string]int {
	p.mu.RLock()
	defer p.mu.RUnlock()

	counts := make(map[string]int)
	for ns, count := range p.policyCounts {
		counts[ns] = count
	}

	return counts
}

